const input = $input.first().json;
const headers = input.headers || {};
const lead = input.body || input;

const expectedSecret = (typeof $env !== 'undefined' && $env.N8N_LEAD_WEBHOOK_SECRET) ? $env.N8N_LEAD_WEBHOOK_SECRET : '';
const providedSecret = headers['x-lead-webhook-secret'] || headers['X-Lead-Webhook-Secret'] || '';

if (expectedSecret && providedSecret !== expectedSecret) {
  return [{
    json: {
      ok: false,
      statusCode: 401,
      error: 'invalid_webhook_secret',
    },
  }];
}

const WOHNUNG_LABELS = {
  '3-zimmer': '3-Zimmer mit Garten (92 m², €329.000)',
  '4-zimmer': '4-Zimmer Dachterrasse (105 m², €359.000)',
  'beide': 'Beide Wohnungen (€688.000)',
};

const ZEITRAHMEN_LABELS = {
  'sofort': 'So schnell wie möglich',
  '3-6-monate': 'In 3–6 Monaten',
  'informieren': 'Informiert sich erst',
};

const EIGENKAPITAL_LABELS = {
  'unter-30k': 'Unter €30.000',
  '30-50k': '€30.000 – €50.000',
  '50-80k': '€50.000 – €80.000',
  'ueber-80k': 'Über €80.000',
  'keine-angabe': 'Keine Angabe',
};

const FINANZIERUNG_LABELS = {
  'vorhanden': 'Ja, vorhanden',
  'in-planung': 'In Planung',
  'benoetigt-hilfe': 'Braucht Unterstützung',
};

function addMinutes(isoDate, minutes) {
  return new Date(new Date(isoDate).getTime() + minutes * 60 * 1000).toISOString();
}

function asBool(value) {
  return value === true || value === 'true' || value === 'yes' || value === 'Ja';
}

function qualify({ leadScore, timeline, equity, financing, underqualified }) {
  const hasMinimumCapital = ['30-50k', '50-80k', 'ueber-80k'].includes(equity);
  const hasStrongCapital = ['50-80k', 'ueber-80k'].includes(equity);
  const isActiveBuyer = ['sofort', '3-6-monate'].includes(timeline);
  const financingReady = financing === 'vorhanden';

  if (underqualified || equity === 'unter-30k') {
    return {
      segment: 'not_qualified',
      status: 'not_qualified',
      priority: 'P4',
      nextAction: 'send_soft_disqualification_or_financing_options',
      assignedTo: 'ai_agent',
      followupMinutes: 4320,
      handoffRequired: false,
      handoffReason: '',
      qualificationReason: 'minimum_equity_not_met',
    };
  }

  if (leadScore === 'hot' || (timeline === 'sofort' && hasStrongCapital && financingReady)) {
    return {
      segment: 'hot',
      status: 'ready_for_call',
      priority: 'P1',
      nextAction: 'call_center_call_within_15min_and_send_expose',
      assignedTo: 'call_center',
      followupMinutes: 15,
      handoffRequired: true,
      handoffReason: 'hot_lead_ready_for_call',
      qualificationReason: 'urgent_timeline_capital_and_financing_ready',
    };
  }

  if (leadScore === 'warm' || (isActiveBuyer && hasMinimumCapital)) {
    return {
      segment: 'warm',
      status: 'ai_follow_up',
      priority: 'P2',
      nextAction: 'send_clarifying_question_and_offer_call',
      assignedTo: 'ai_agent',
      followupMinutes: 120,
      handoffRequired: false,
      handoffReason: '',
      qualificationReason: 'active_buyer_but_financing_or_timing_needs_clarity',
    };
  }

  return {
    segment: 'cold',
    status: 'nurture',
    priority: 'P3',
    nextAction: 'send_nurture_email',
    assignedTo: 'nurture_agent',
    followupMinutes: 1440,
    handoffRequired: false,
    handoffReason: '',
    qualificationReason: 'early_research_or_missing_financing_signal',
  };
}

function emailDraft({ firstName, segment, wohnungLabel, timelineLabel, equityLabel, financingLabel }) {
  const greeting = firstName ? 'Hallo ' + firstName + ',' : 'Hallo,';
  const objectLine = wohnungLabel ? 'zur ' + wohnungLabel : 'zu Ihrer Anfrage';

  if (segment === 'hot') {
    return {
      email_subject: 'Ihr Exposé und ein kurzer Abstimmungstermin',
      email_draft: greeting + '\n\nvielen Dank für Ihr Interesse ' + objectLine + '. Ihre Angaben passen sehr gut zu einem kurzfristigen Beratungsgespräch.\n\nDarf unser Team Sie heute kurz telefonisch erreichen, um die nächsten Schritte und verfügbare Besichtigungstermine abzustimmen?\n\nViele Grüße\nNovaHaus Immobilien',
    };
  }

  if (segment === 'warm') {
    return {
      email_subject: 'Kurze Rückfrage zu Ihrer Finanzierung',
      email_draft: greeting + '\n\nvielen Dank für Ihre Anfrage ' + objectLine + '. Damit wir Ihnen direkt die passenden nächsten Schritte senden können: Haben Sie bereits mit einer Bank oder einem Finanzierungsberater über den Kauf gesprochen?\n\nIhre Angaben: ' + timelineLabel + ', ' + equityLabel + ', ' + financingLabel + '.\n\nWenn Sie möchten, können wir danach einen kurzen Telefontermin mit unserem Team koordinieren.\n\nViele Grüße\nNovaHaus Immobilien',
    };
  }

  if (segment === 'not_qualified') {
    return {
      email_subject: 'Ihre Anfrage bei NovaHaus Immobilien',
      email_draft: greeting + '\n\nvielen Dank für Ihr Interesse ' + objectLine + '. Für dieses Angebot empfehlen wir in der Regel mehr Eigenkapital, damit die Finanzierung realistisch geprüft werden kann.\n\nWir können Ihnen aber gern alternative Optionen oder Hinweise zur Finanzierungsvorbereitung senden.\n\nViele Grüße\nNovaHaus Immobilien',
    };
  }

  return {
    email_subject: 'Weitere Informationen zu Ihrer Immobiliensuche',
    email_draft: greeting + '\n\nvielen Dank für Ihre Anfrage ' + objectLine + '. Wir senden Ihnen gern weitere Informationen und halten Sie zu passenden Angeboten auf dem Laufenden.\n\nFalls Ihr Kaufzeitraum konkreter wird oder Sie Ihre Finanzierung klären möchten, antworten Sie einfach kurz auf diese E-Mail.\n\nViele Grüße\nNovaHaus Immobilien',
  };
}

const createdAt = lead.created_at || lead.timestamp || new Date().toISOString();
const firstName = lead.first_name || lead.firstName || '';
const lastName = lead.last_name || lead.lastName || '';
const timeline = lead.purchase_timeline || lead.zeitrahmen || '';
const equity = lead.equity_bucket || lead.eigenkapital || '';
const financing = lead.financing_status || lead.finanzierung || '';
const underqualified = asBool(lead.underqualified);
const rawScore = lead.original_score || lead.lead_score || lead.score || lead.segment || 'cold';
const qualification = qualify({ leadScore: rawScore, timeline, equity, financing, underqualified });
const wohnungLabel = lead.wohnung_label || WOHNUNG_LABELS[lead.wohnung] || lead.wohnung || '';
const timelineLabel = lead.purchase_timeline_label || ZEITRAHMEN_LABELS[timeline] || timeline;
const equityLabel = lead.equity_bucket_label || EIGENKAPITAL_LABELS[equity] || equity;
const financingLabel = lead.financing_status_label || FINANZIERUNG_LABELS[financing] || financing;
const draft = lead.email_draft && lead.email_subject
  ? { email_subject: lead.email_subject, email_draft: lead.email_draft }
  : emailDraft({ firstName, segment: qualification.segment, wohnungLabel, timelineLabel, equityLabel, financingLabel });

const row = {
  created_at: createdAt,
  lead_id: lead.lead_id || '',
  status: lead.status || qualification.status,
  segment: qualification.segment,
  score: qualification.segment,
  next_best_action: lead.next_best_action || lead.next_action || qualification.nextAction,
  handoff_required: (lead.handoff_required ?? qualification.handoffRequired) ? 'yes' : 'no',
  handoff_reason: lead.handoff_reason || qualification.handoffReason,
  name: lead.name || (firstName + ' ' + lastName).trim(),
  first_name: firstName,
  last_name: lastName,
  email: lead.email || '',
  phone: lead.phone || '',
  wohnung: wohnungLabel,
  purchase_timeline: timelineLabel,
  equity_bucket: equityLabel,
  financing_status: financingLabel,
  underqualified: underqualified ? 'yes' : 'no',
  consent_contact: asBool(lead.consent_contact ?? lead.consent) ? 'yes' : 'no',
  consent_data_processing: asBool(lead.consent_data_processing ?? lead.consent) ? 'yes' : 'no',
  utm_source: lead.utm_source || (lead.source && lead.source.utm_source) || '',
  utm_medium: lead.utm_medium || (lead.source && lead.source.utm_medium) || '',
  utm_campaign: lead.utm_campaign || (lead.source && lead.source.utm_campaign) || '',
  utm_content: lead.utm_content || (lead.source && lead.source.utm_content) || '',
  utm_term: lead.utm_term || (lead.source && lead.source.utm_term) || '',
  priority: lead.priority || qualification.priority,
  next_action: lead.next_action || lead.next_best_action || qualification.nextAction,
  followup_due_at: lead.followup_due_at || addMinutes(createdAt, qualification.followupMinutes),
  assigned_to: lead.assigned_to || qualification.assignedTo,
  qualification_reason: lead.qualification_reason || qualification.qualificationReason,
  lead_summary: lead.lead_summary || 'Objekt: ' + (wohnungLabel || 'nicht angegeben') + ' | Zeitrahmen: ' + (timelineLabel || 'nicht angegeben') + ' | Eigenkapital: ' + (equityLabel || 'nicht angegeben') + ' | Finanzierung: ' + (financingLabel || 'nicht angegeben'),
  email_subject: draft.email_subject,
  email_draft: draft.email_draft,
};

return [{ json: { ok: true, statusCode: 200, lead, row } }];

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_path: "hot_call_center",
    manager_task: "Call-center: call within 15 minutes and confirm handoff",
  },
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_path: "warm_ai_email_draft",
    manager_task: "AI agent: prepare clarifying email and offer a call",
  },
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_path: "cold_nurture",
    manager_task: "AI agent: add to nurture follow-up",
  },
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_path: "not_qualified_soft_filter",
    manager_task: "AI agent: send soft rejection or financing options, no call-center handoff",
  },
}));
